entry.content:
题目：给你一个由若干 0 和 1 组成的二维网格 grid，请你找出边界全部由 1 组成的最大 正方形 子网格，并返回该子网格中的元素数量。如果不存在，则返回 0。 示例：示例 1： 输入：grid = [[1,1,1],[1,0,1],[1,1,1]] 输出：9 示例 2： 输入：grid = [[1,1,0,0]] 输出：1 提示： 1 &lt;= grid.length &lt;= 100 1 &lt;= grid[0].length &lt;= 100 grid[i][j] 为 0 或 1 分析：存储每一个点往上和往左连续的1 从每个点左侧连续的第一个1开始遍历，判断是否可以构成正方形 代码：class Solution { public: int largest1BorderedSquare(vector&lt;vector&lt;int&gt;&gt;&amp; grid) { int g[grid.size()][grid[0].size()] = {0}; int g1[grid.size()][grid[0].size()] = {0}; //cout &lt;&lt; g[0][1] &lt;&lt; &quot;
&quot;; int m = 1; bool b = true; for(int i = 0; i &lt; grid.size() &amp;&amp; b; i++){ for(int j = 0; j &lt; grid[0].size() &amp;&amp; b; j++){ if(grid[i][j] == 1) b = false; } } for(int i = 0; i &lt; grid.size(); i++){ for(int j = 0; j &lt; grid[0].size(); j++){ g[i][j] = 0; //cout &lt;&lt; g[i][j] &lt;&lt; &quot; &quot;; } //cout &lt;&lt; &quot;
&quot;; } //cout &lt;&lt; &quot;
&quot;; if(b) return 0; if(grid.size() == 1 || grid[0].size() == 1) return 1; for(int i = 0; i &lt; grid.size(); i++){ for(int j = 0; j &lt; grid[0].size(); j++){ if(grid[i][j] == 1){ if(j != 0) g[i][j] = g[i][j-1] + 1; else g[i][j] = 1; } } } for(int i = 0; i &lt; grid.size(); i++){ for(int j = 0; j &lt; grid[0].size(); j++){ if(grid[i][j] == 1){ if(i != 0) g1[i][j] = g1[i-1][j] + 1; else g1[i][j] = 1; } } } // for(int i = 0; i &lt; grid.size(); i++){ // for(int j = 0; j &lt; grid[0].size(); j++){ // cout &lt;&lt; g1[i][j] &lt;&lt; &quot; &quot;; // } // cout &lt;&lt; &quot;
&quot;; // } //cout &lt;&lt; g[0][1] &lt;&lt; &quot;
&quot;; for(int i = 0; i &lt; grid.size(); i++){ for(int j = 0; j &lt; grid[0].size(); j++){ for(int k = j - g[i][j] + 1; k &lt; j; k++){ //cout &lt;&lt; k &lt;&lt; &quot; &quot;; if(i+j-k &lt; grid.size() &amp;&amp; g[i+j-k][j] &gt;= j - k &amp;&amp; g1[i+j-k][k] &gt;= j - k &amp;&amp; g1[i+j-k][j] &gt;= j - k){ m = max(m, (j - k+1) * (j - k+1)); } } } } return m; } }; 题目地址：https://leetcode-cn.com/contest/weekly-contest-147/problems/largest-1-bordered-square/
